<template>
    <div class="index">
        <h1>我的族谱</h1>
        <div class="list">
            <ul>
                <router-link tag="li" v-for="item in family" :to="'/family/'+item.id">
                    <div class="tools" v-if="item.id!=1">
                        <i class="edit el-icon-s-tools" @click.stop="edit(item)"></i>
                        <i class="edit el-icon-delete-solid" @click.stop="del(item)"></i>
                    </div>
                    <h2>{{item.name}}</h2>
                    <div style="display: flex;padding-top: 1vw;flex-wrap: wrap">
                        <el-statistic
                                :value="totalPerson(item.tree)"
                                title="人数"
                        >
                        </el-statistic>
                        <el-statistic
                                :value="maleNum(item.tree)"
                                title="男"
                        >
                        </el-statistic>
                        <el-statistic
                                :value="femaleNum(item.tree)"
                                title="女"
                        >
                        </el-statistic>
                        <el-statistic
                                :value="liveNum(item.tree)"
                                title="健在"
                        >
                        </el-statistic>
                        <el-statistic
                                :value="deathNum(item.tree)"
                                title="已故"
                        >
                        </el-statistic>
                    </div>
                </router-link>
                <li class="add" @click="add"><i class="el-icon-plus"></i></li>
            </ul>
        </div>
        <el-dialog
                :title="whichTitle"
                :visible.sync="showEditDialog"
                :close-on-click-modal="false"
        >
            <el-form :model="editForm" status-icon :rules="rules" ref="editForm" label-width="80px">
                <el-form-item label="家谱名称" prop="name">
                    <el-input v-model="editForm.name"></el-input>
                </el-form-item>
                <el-form-item>
                    <el-button type="primary" @click="submitForm('editForm')">提交</el-button>
                </el-form-item>
            </el-form>
        </el-dialog>
    </div>
</template>

<script>
    export default {
        name: 'index',
        data() {
            let validateName = (rule, value, callback) => {
                if (value === '') {
                    callback(new Error('请输入家谱名称'));
                } else {
                    callback();
                }
            };
            return {
                family: null,
                familyPlainData: null,
                showEditDialog: false,
                currentFamily: null,
                editMode: 'add', // 'add' 或 'edit'
                editForm: {
                    name: '',
                    id: ''
                },
                rules: {
                    name: [
                        {required: true, validator: validateName, trigger: 'blur'}
                    ],
                },
            }
        },
        mounted() {
            this.getBase()
            if (this.$store.state.family.family === null) {
                this.$store.dispatch('family/getAll').then((rs) => {
                    this.family = rs
                })
            } else {
                this.family = this.$store.state.family.family
            }
        },
        watch: {},
        computed: {
            whichTitle() {
                if (this.editMode === 'edit') {
                    return '修改家谱'
                } else {
                    return '新建一个家谱'
                }
            }
        },
        methods: {
            async getBase() {
                const {createClient} = supabase
                this.base = createClient('https://pmfxqcqvqrhxnxyotyzp.supabase.co', 'sb_publishable_T98PsjOazNXjyak2nXPwDg_ox52NaWg')
            },
            treeToFlat(tree, result = []) {
                tree.forEach(node => {
                    const {id, name, photo, gender, parent, spouse, details, children, birthDate, deathDate} = node; // 解构并保留其他属性
                    result.push({id, name, photo, gender, parent, details, birthDate, deathDate});
                    spouse.forEach((sp) => {
                        const {id, spid, name, photo, gender, details, birthDate, deathDate} = sp; // 解构并保留其他属性
                        result.push({id, spid, name, photo, gender, details, birthDate, deathDate});
                    })
                    if (children && children.length > 0) {
                        this.treeToFlat(children, result);
                    }
                });
                return result;
            },
            getPlainData(data) {
                if (data) {
                    //转为PLAIN数据
                    let array = []
                    const {id, name, photo, gender, parent, details, birthDate, deathDate} = data;
                    array.push({id, name, photo, gender, parent, details, birthDate, deathDate});
                    if (data.spouse) {
                        data.spouse.forEach((sp) => {
                            const {id, spid, name, photo, gender, details, birthDate, deathDate} = sp; // 解构并保留其他属性
                            array.push({id, spid, name, photo, gender, details, birthDate, deathDate});
                        })

                    }
                    let fi1
                    if (data.children) {
                        fi1 = this.treeToFlat(data.children, [])
                        array.push(...fi1)
                    }
                    return array
                } else {
                    return []
                }

            },
            totalPerson(data) {
                let result = this.getPlainData(data)
                if (result) {
                    return result.length
                }

            },
            maleNum(data) {
                let result = this.getPlainData(data)
                if (result) {
                    let fi = result.filter((el) => {
                        return el.gender === 'male'
                    })
                    return fi.length
                }
            },
            femaleNum(data) {
                let result = this.getPlainData(data)
                if (result) {
                    let fi = result.filter((el) => {
                        return el.gender === 'female'
                    })
                    return fi.length
                }
            },
            liveNum(data) {
                let result = this.getPlainData(data)
                if (result) {
                    let fi = result.filter((el) => {
                        return el.deathDate === ''
                    })
                    return fi.length
                }
            },
            deathNum(data) {
                let result = this.getPlainData(data)
                if (result) {
                    let fi = result.filter((el) => {
                        return el.deathDate != ''
                    })
                    return fi.length
                }
            },
            add() {
                this.editForm.name = ''
                this.editForm.id = ''
                this.editMode = 'add'
                this.showEditDialog = true
            },
            edit(item) {
                this.editMode = 'edit'
                this.editForm.name = item.name
                this.editForm.id = item.id
                this.showEditDialog = true
                this.currentFamily = item
            },
            submitForm(formName) {
                this.$refs[formName].validate((valid) => {
                    if (valid) {
                        this.saveEdit()

                    } else {
                        return false;
                    }
                });
            },
            async saveEdit() {
                if (this.editMode === 'add') {
                    let id = this.getId()
                    let colors = {
                        bg: '#FAF9F5',
                        fbg: '#F7C7DF',
                        mbg: '#AFD1ED',
                        deathbg: '#fff',
                        line: '#666',
                        fline: '#DE6BA6',
                        mline: '#5f92bd',
                        deathline: '#aaa',
                    }
                    this.family.unshift({name: this.editForm.name, id})
                    await this.base.from('familytree').insert({
                        id,
                        name: this.editForm.name,
                        colors
                    })
                    this.$message({
                    message: '添加成功',
                    type: 'success'
                });

                } else if (this.editMode === 'edit') {
                    this.currentFamily.name = this.editForm.name
                    await this.base.from('familytree').update({'name': this.editForm.name}).eq('id', this.editForm.id)
                    this.$message({
                    message: '修改除成功',
                    type: 'success'
                });
                }
                this.showEditDialog = false
                await this.$store.dispatch('family/getAll')
            },
            async del(data) {
                let index = this.family.indexOf(data)
                this.family.splice(index, 1)
                const {item} = await this.base
                    .from('familytree')
                    .delete()
                    .eq('id', data.id)
                this.$message({
                    message: '删除成功',
                    type: 'success'
                });
                await this.$store.dispatch('family/getAll')
            },
            getId() {
                let id
                if (this.family.length > 0) {
                    let maxObject = this.family.reduce((prev, current) => (prev.id > current.id ? prev : current));
                    id = maxObject.id + 1
                } else {
                    id = 1
                }
                return id
            },


        }
    }
</script>
<style>
    .el-statistic {
        display: flex;
        flex-direction: column;
        gap: 6px;
        padding-bottom: 10px;
    }

    .el-statistic .con .number {
        color: #5F92BDFF;
        font-size: calc(clamp(30px, 3vw, 50px) * 0.5);
    }
</style>
<style scoped>
    .index {
        width: 100%;
        max-width: 1000px;
        margin: 0 auto;
        padding: 15px;
        display: flex;
        flex-direction: column;
        gap: 2vw
    }

    .index h1 {
        font-size: clamp(30px, 3vw, 50px);
        font-weight: 700;
        padding-top: 3vw;
    }

    .index .list ul {
        display: flex;
        align-items: stretch;
        flex-wrap: wrap;
        gap: 1vw;
        width: calc(100% + 1vw);
    }

    .index .list ul li {
        background: var(--white);
        border: solid 1px #ddd;
        width: calc(33.33% - 1vw);
        border-radius: 8px;
        padding: 1vw 2vw;
        cursor: pointer;
        position: relative;
    }

    .index .list ul li .tools {
        position: absolute;
        right: 2vw;
        top: 1.5vw;
        display: flex;
        align-items: center;
        flex-direction: row;
        z-index: 1;
    }

    .index .list ul li .tools i {
        font-size: calc(clamp(30px, 3vw, 50px) * 0.3);
        color: var(--deathline);
    }


    .index .list ul li h2 {
        font-weight: 500;
        font-size: calc(clamp(30px, 3vw, 50px) * 0.6);
    }

    .index .list ul li .el-statistic {
        width: 20%;
    }

    .index .list ul li.add {
        display: flex;
        align-items: center;
        justify-content: center;
    }

    .index .list ul li.add i {
        font-size: 3vw;
        color: #5F92BDFF;
    }


    @media (max-width: 768px) {
        .index .list ul {
            gap: 3vw;
            width: calc(100% + 3vw);

        }

        .index .list ul li {
            width: calc(50% - 3vw);
        }

        .index .list ul li.add i {
            font-size: 6vw;
        }

    }
</style>

